        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public IReadOnlyList<Course> SearchCourses(string? query, int? departmentId)
    {
        var results = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            results = results.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(query))
        {
            var q = query.Trim();
            results = results.Where(c =>
                c.Title.Contains(q, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(q, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(q, StringComparison.OrdinalIgnoreCase));
        }

        return results.ToList();
