        };
    }

    public IReadOnlyList<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public IReadOnlyList<Instructor> GetInstructors() => _instructors;

    public Instructor? GetInstructor(int id) => _instructors.FirstOrDefault(i => i.Id == id);

    public IReadOnlyList<Course> GetAllCourses() => _courses;

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public IReadOnlyList<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public IReadOnlyList<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public IReadOnlyList<Course> SearchCourses(string? query, int? departmentId)
    {
        var results = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            results = results.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(query))
        {
            var q = query.Trim();
            results = results.Where(c =>
                c.Title.Contains(q, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(q, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(q, StringComparison.OrdinalIgnoreCase));
        }

        return results.ToList();
    }
}

