@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Course Catalog</PageTitle>

<h1 class="mb-4">Course Catalog</h1>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="q" value="@Query" class="form-control" placeholder="Search by title, code, or keyword…" />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                if (dept.Id == DepartmentId)
                {
                    <option value="@dept.Id" selected>@dept.Name (@dept.Code)</option>
                }
                else
                {
                    <option value="@dept.Id">@dept.Name (@dept.Code)</option>
                }
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <p class="text-muted mb-3">Showing @courses.Count course(s)</p>
    <div class="table-responsive">
        <table class="table table-striped table-hover align-middle">
            <thead class="table-dark">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Schedule</th>
                    <th>Enrollment</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    var dept = Catalog.GetDepartment(course.DepartmentId);
                    var pct = course.MaxEnrollment > 0 ? (int)(100.0 * course.CurrentEnrollment / course.MaxEnrollment) : 0;
                    <tr>
                        <td><strong>@course.Code</strong></td>
                        <td><a href="@($"courses/{course.Id}")">@course.Title</a></td>
                        <td>@dept?.Name</td>
                        <td>@course.Credits</td>
                        <td><small>@course.Schedule</small></td>
                        <td>
                            <div class="progress" style="min-width: 80px; height: 20px;" title="@course.CurrentEnrollment / @course.MaxEnrollment">
                                <div class="progress-bar @(pct >= 90 ? "bg-danger" : pct >= 70 ? "bg-warning" : "bg-success")"
                                     role="progressbar" style="width: @(pct)%;">
                                    @course.CurrentEnrollment/@course.MaxEnrollment
                                </div>
                            </div>
                        </td>
                        <td><a href="@($"courses/{course.Id}")" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery(Name = "q")]
    public string? Query { get; set; }

    [SupplyParameterFromQuery(Name = "departmentId")]
    public int? DepartmentId { get; set; }

    private IReadOnlyList<Department> departments = [];
    private IReadOnlyList<Course> courses = [];

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.SearchCourses(Query, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-primary">Back to Course Catalog</a>
}
else
{
    <PageTitle>@course.Code — @course.Title</PageTitle>

    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="">Home</a></li>
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1>@course.Code — @course.Title</h1>
            <span class="badge bg-primary me-1">@course.Credits Credits</span>
            <span class="badge bg-secondary me-1">@course.Semester</span>
            @{
                var pct = course.MaxEnrollment > 0 ? (int)(100.0 * course.CurrentEnrollment / course.MaxEnrollment) : 0;
            }
            <span class="badge @(pct >= 90 ? "bg-danger" : pct >= 70 ? "bg-warning text-dark" : "bg-success")">
                @course.CurrentEnrollment / @course.MaxEnrollment enrolled
            </span>

            <hr />

            <h4>Description</h4>
            <p class="lead">@course.Description</p>

            <h4>Schedule &amp; Location</h4>
            <table class="table table-bordered w-auto">
                <tr><th>Schedule</th><td>@course.Schedule</td></tr>
                <tr><th>Location</th><td>@course.Location</td></tr>
                <tr><th>Semester</th><td>@course.Semester</td></tr>
                <tr><th>Department</th><td><a href="@($"courses?departmentId={department?.Id}")">@department?.Name</a></td></tr>
            </table>

            <a href="@($"enroll?courseId={course.Id}")" class="btn btn-success btn-lg mt-2">Enroll in This Course</a>
            <a href="courses" class="btn btn-outline-secondary btn-lg mt-2 ms-2">Back to Catalog</a>
        </div>

        <div class="col-lg-4 mt-4 mt-lg-0">
            @if (instructor is not null)
            {
                <div class="card shadow-sm">
                    <div class="card-header bg-dark text-white">
                        <h5 class="mb-0">👤 Instructor</h5>
                    </div>
                    <div class="card-body">
                        <h5>@instructor.Name</h5>
                        <p class="text-muted mb-2">@instructor.Title</p>
                        <p>@instructor.Bio</p>
                        <hr />
                        <p class="mb-1"><strong>Email:</strong> @instructor.Email</p>
                        <p class="mb-0"><strong>Office:</strong> @instructor.Office</p>
                    </div>
                </div>
            }
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;
    private Department? department;
    private Instructor? instructor;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
        if (course is not null)
        {
            department = Catalog.GetDepartment(course.DepartmentId);
            instructor = Catalog.GetInstructor(course.InstructorId);
        }
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

<div class="row">
    <div class="col-lg-8">
        <div class="card shadow-sm">
            <div class="card-body">
                <p class="text-muted">Fill out the form below to submit an enrollment request. You will receive confirmation once your request is processed.</p>

                <EditForm Model="request" FormName="enrollment" method="post" OnValidSubmit="HandleSubmit">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger mb-3" />

                    <div class="mb-3">
                        <label for="studentName" class="form-label">Full Name <span class="text-danger">*</span></label>
                        <InputText id="studentName" @bind-Value="request.StudentName" class="form-control" placeholder="e.g. Jane Doe" />
                        <ValidationMessage For="() => request.StudentName" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                        <InputText id="studentId" @bind-Value="request.StudentId" class="form-control" placeholder="e.g. STU123456" />
                        <ValidationMessage For="() => request.StudentId" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
                        <InputSelect id="courseId" @bind-Value="request.CourseId" class="form-select">
                            <option value="0">-- Select a course --</option>
                            @foreach (var course in courses)
                            {
                                <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr.)</option>
                            }
                        </InputSelect>
                        <ValidationMessage For="() => request.CourseId" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="comments" class="form-label">Comments (optional)</label>
                        <InputTextArea id="comments" @bind-Value="request.Comments" class="form-control" rows="3" placeholder="Any additional information…" />
                        <ValidationMessage For="() => request.Comments" class="text-danger" />
                    </div>

                    <button type="submit" class="btn btn-primary btn-lg">Submit Enrollment Request</button>
                </EditForm>
            </div>
        </div>
    </div>

    <div class="col-lg-4 mt-4 mt-lg-0">
        <div class="card bg-light">
            <div class="card-body">
                <h5 class="card-title">ℹ️ How It Works</h5>
                <ol class="mb-0">
                    <li>Fill out the form with your details.</li>
                    <li>Select the course you want to enroll in.</li>
                    <li>Submit the request.</li>
                    <li>You'll receive a confirmation with your request details.</li>
                </ol>
            </div>
        </div>
    </div>
</div>

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest request { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    public int? PreselectedCourseId { get; set; }

    private IReadOnlyList<Course> courses = [];
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = Catalog.GetAllCourses();

        if (PreselectedCourseId.HasValue && request.CourseId == 0)
        {
            request.CourseId = PreselectedCourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        submitted = true;
    }
}

