@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Course Catalog</PageTitle>

<h1 class="mb-4">Course Catalog</h1>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="q" value="@Query" class="form-control" placeholder="Search by title, code, or keyword…" />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                if (dept.Id == DepartmentId)
                {
                    <option value="@dept.Id" selected>@dept.Name (@dept.Code)</option>
                }
                else
                {
                    <option value="@dept.Id">@dept.Name (@dept.Code)</option>
                }
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <p class="text-muted mb-3">Showing @courses.Count course(s)</p>
    <div class="table-responsive">
        <table class="table table-striped table-hover align-middle">
            <thead class="table-dark">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Schedule</th>
                    <th>Enrollment</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    var dept = Catalog.GetDepartment(course.DepartmentId);
                    var pct = course.MaxEnrollment > 0 ? (int)(100.0 * course.CurrentEnrollment / course.MaxEnrollment) : 0;
                    <tr>
                        <td><strong>@course.Code</strong></td>
                        <td><a href="@($"courses/{course.Id}")">@course.Title</a></td>
                        <td>@dept?.Name</td>
                        <td>@course.Credits</td>
                        <td><small>@course.Schedule</small></td>
                        <td>
                            <div class="progress" style="min-width: 80px; height: 20px;" title="@course.CurrentEnrollment / @course.MaxEnrollment">
                                <div class="progress-bar @(pct >= 90 ? "bg-danger" : pct >= 70 ? "bg-warning" : "bg-success")"
                                     role="progressbar" style="width: @(pct)%;">
                                    @course.CurrentEnrollment/@course.MaxEnrollment
                                </div>
                            </div>
                        </td>
                        <td><a href="@($"courses/{course.Id}")" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery(Name = "q")]
    public string? Query { get; set; }

    [SupplyParameterFromQuery(Name = "departmentId")]
    public int? DepartmentId { get; set; }

    private IReadOnlyList<Department> departments = [];
    private IReadOnlyList<Course> courses = [];

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.SearchCourses(Query, DepartmentId);
    }
}

