﻿@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<div class="hero-banner mb-4 p-4 rounded-3 text-white" style="background: linear-gradient(135deg, #1b3a5c 0%, #2a6496 100%);">
    <h1 class="display-5 fw-bold">📚 University Course Catalog</h1>
    <p class="lead mb-3">Explore departments, discover courses, and enroll for Fall 2026.</p>
    <a class="btn btn-light btn-lg me-2" href="courses">Browse All Courses</a>
    <a class="btn btn-outline-light btn-lg" href="enroll">Enroll Now</a>
</div>

<h2 class="mb-3">⭐ Featured Courses</h2>
<div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3 mb-5">
    @foreach (var course in featuredCourses)
    {
        var dept = Catalog.GetDepartment(course.DepartmentId);
        <div class="col">
            <div class="card h-100 shadow-sm">
                <div class="card-body">
                    <h5 class="card-title">
                        <a href="@($"courses/{course.Id}")">@course.Code — @course.Title</a>
                    </h5>
                    <p class="card-text text-muted mb-1">@dept?.Name · @course.Credits credits</p>
                    <p class="card-text">@Truncate(course.Description, 120)</p>
                </div>
                <div class="card-footer bg-transparent d-flex justify-content-between align-items-center">
                    <small class="text-muted">@course.Schedule</small>
                    <a href="@($"courses/{course.Id}")" class="btn btn-sm btn-outline-primary">Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mb-3">🏛️ Departments</h2>
<div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3 mb-4">
    @foreach (var dept in departments)
    {
        var courseCount = Catalog.GetCoursesByDepartment(dept.Id).Count;
        <div class="col">
            <div class="card h-100 shadow-sm">
                <div class="card-body">
                    <h5 class="card-title">
                        <a href="@($"courses?departmentId={dept.Id}")">@dept.Name</a>
                    </h5>
                    <p class="card-text text-muted mb-1">@dept.Code · @courseCount course(s)</p>
                    <p class="card-text">@dept.Description</p>
                </div>
                <div class="card-footer bg-transparent">
                    <a href="@($"courses?departmentId={dept.Id}")" class="btn btn-sm btn-outline-secondary">View Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private IReadOnlyList<Course> featuredCourses = [];
    private IReadOnlyList<Department> departments = [];

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

