@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-primary">Back to Course Catalog</a>
}
else
{
    <PageTitle>@course.Code — @course.Title</PageTitle>

    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="">Home</a></li>
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1>@course.Code — @course.Title</h1>
            <span class="badge bg-primary me-1">@course.Credits Credits</span>
            <span class="badge bg-secondary me-1">@course.Semester</span>
            @{
                var pct = course.MaxEnrollment > 0 ? (int)(100.0 * course.CurrentEnrollment / course.MaxEnrollment) : 0;
            }
            <span class="badge @(pct >= 90 ? "bg-danger" : pct >= 70 ? "bg-warning text-dark" : "bg-success")">
                @course.CurrentEnrollment / @course.MaxEnrollment enrolled
            </span>

            <hr />

            <h4>Description</h4>
            <p class="lead">@course.Description</p>

            <h4>Schedule &amp; Location</h4>
            <table class="table table-bordered w-auto">
                <tr><th>Schedule</th><td>@course.Schedule</td></tr>
                <tr><th>Location</th><td>@course.Location</td></tr>
                <tr><th>Semester</th><td>@course.Semester</td></tr>
                <tr><th>Department</th><td><a href="@($"courses?departmentId={department?.Id}")">@department?.Name</a></td></tr>
            </table>

            <a href="@($"enroll?courseId={course.Id}")" class="btn btn-success btn-lg mt-2">Enroll in This Course</a>
            <a href="courses" class="btn btn-outline-secondary btn-lg mt-2 ms-2">Back to Catalog</a>
        </div>

        <div class="col-lg-4 mt-4 mt-lg-0">
            @if (instructor is not null)
            {
                <div class="card shadow-sm">
                    <div class="card-header bg-dark text-white">
                        <h5 class="mb-0">👤 Instructor</h5>
                    </div>
                    <div class="card-body">
                        <h5>@instructor.Name</h5>
                        <p class="text-muted mb-2">@instructor.Title</p>
                        <p>@instructor.Bio</p>
                        <hr />
                        <p class="mb-1"><strong>Email:</strong> @instructor.Email</p>
                        <p class="mb-0"><strong>Office:</strong> @instructor.Office</p>
                    </div>
                </div>
            }
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;
    private Department? department;
    private Instructor? instructor;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
        if (course is not null)
        {
            department = Catalog.GetDepartment(course.DepartmentId);
            instructor = Catalog.GetInstructor(course.InstructorId);
        }
    }
}

