@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

<div class="row">
    <div class="col-lg-8">
        <div class="card shadow-sm">
            <div class="card-body">
                <p class="text-muted">Fill out the form below to submit an enrollment request. You will receive confirmation once your request is processed.</p>

                <EditForm Model="request" FormName="enrollment" method="post" OnValidSubmit="HandleSubmit">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger mb-3" />

                    <div class="mb-3">
                        <label for="studentName" class="form-label">Full Name <span class="text-danger">*</span></label>
                        <InputText id="studentName" @bind-Value="request.StudentName" class="form-control" placeholder="e.g. Jane Doe" />
                        <ValidationMessage For="() => request.StudentName" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                        <InputText id="studentId" @bind-Value="request.StudentId" class="form-control" placeholder="e.g. STU123456" />
                        <ValidationMessage For="() => request.StudentId" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
                        <InputSelect id="courseId" @bind-Value="request.CourseId" class="form-select">
                            <option value="0">-- Select a course --</option>
                            @foreach (var course in courses)
                            {
                                <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr.)</option>
                            }
                        </InputSelect>
                        <ValidationMessage For="() => request.CourseId" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="comments" class="form-label">Comments (optional)</label>
                        <InputTextArea id="comments" @bind-Value="request.Comments" class="form-control" rows="3" placeholder="Any additional information…" />
                        <ValidationMessage For="() => request.Comments" class="text-danger" />
                    </div>

                    <button type="submit" class="btn btn-primary btn-lg">Submit Enrollment Request</button>
                </EditForm>
            </div>
        </div>
    </div>

    <div class="col-lg-4 mt-4 mt-lg-0">
        <div class="card bg-light">
            <div class="card-body">
                <h5 class="card-title">ℹ️ How It Works</h5>
                <ol class="mb-0">
                    <li>Fill out the form with your details.</li>
                    <li>Select the course you want to enroll in.</li>
                    <li>Submit the request.</li>
                    <li>You'll receive a confirmation with your request details.</li>
                </ol>
            </div>
        </div>
    </div>
</div>

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest request { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
