    private IReadOnlyList<Course> courses = [];
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = Catalog.GetAllCourses();

        if (PreselectedCourseId.HasValue && request.CourseId == 0)
        {
            request.CourseId = PreselectedCourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        submitted = true;
    }
}

